    COMPLETED: {
      label: '�S& Hoàn thành',
      class: 'status-active'
    }
  };
  const s = (status || 'PENDING').toString().toUpperCase();
  const badge = statusMap[s] || statusMap.PENDING;
  return <span className={badge.class}>{badge.label}</span>;
